diff --git a/llvm/lib/Transforms/IPO/FunctionAttrs.cpp b/llvm/lib/Transforms/IPO/FunctionAttrs.cpp
index bbfed2ac2c09..07a36313aeaa 100644
--- a/llvm/lib/Transforms/IPO/FunctionAttrs.cpp
+++ b/llvm/lib/Transforms/IPO/FunctionAttrs.cpp
@@ -656,28 +656,39 @@ ArgumentAccessInfo getArgumentAccessInfo(const Instruction *I,
                                          const ArgumentUse &ArgUse,
                                          const DataLayout &DL) {
   auto GetTypeAccessRange =
-      [&DL](Type *Ty,
-            std::optional<int64_t> Offset) -> std::optional<ConstantRange> {
-    auto TypeSize = DL.getTypeStoreSize(Ty);
-    if (!TypeSize.isScalable() && Offset) {
-      int64_t Size = TypeSize.getFixedValue();
-      return ConstantRange(APInt(64, *Offset, true),
-                           APInt(64, *Offset + Size, true));
-    }
-    return std::nullopt;
-  };
+    [&DL](Type *Ty,
+          std::optional<int64_t> Offset) -> std::optional<ConstantRange> {
+  auto TypeSize = DL.getTypeStoreSize(Ty);
+  if (!TypeSize.isScalable() && Offset) {
+    uint64_t Size = TypeSize.getFixedValue();
+    if (Size > 0x7FFFFFFFFFFFFFFFULL) // INT64_MAX
+      return std::nullopt;
+    APInt Lower(64, *Offset, true);
+    APInt Upper = Lower;
+    bool Overflow = false;
+    Upper = Upper.sadd_ov(APInt(64, Size, true), Overflow);
+    if (Overflow)
+      return std::nullopt;
+    return ConstantRange(Lower, Upper);
+  }
+  return std::nullopt;
+};
   auto GetConstantIntRange =
-      [](Value *Length,
-         std::optional<int64_t> Offset) -> std::optional<ConstantRange> {
-    auto *ConstantLength = dyn_cast<ConstantInt>(Length);
-    if (ConstantLength && Offset &&
-        ConstantLength->getValue().isStrictlyPositive()) {
-      return ConstantRange(
-          APInt(64, *Offset, true),
-          APInt(64, *Offset + ConstantLength->getSExtValue(), true));
-    }
-    return std::nullopt;
-  };
+    [](Value *Length,
+       std::optional<int64_t> Offset) -> std::optional<ConstantRange> {
+  auto *ConstantLength = dyn_cast<ConstantInt>(Length);
+  if (ConstantLength && Offset &&
+      ConstantLength->getValue().isStrictlyPositive()) {
+    APInt Lower(64, *Offset, true);
+    APInt Upper = Lower;
+    bool Overflow = false;
+    Upper = Upper.sadd_ov(ConstantLength->getValue().sextOrTrunc(64), Overflow);
+    if (Overflow)
+      return std::nullopt;
+    return ConstantRange(Lower, Upper);
+  }
+  return std::nullopt;
+};
   if (auto *SI = dyn_cast<StoreInst>(I)) {
     if (SI->isSimple() && &SI->getOperandUse(1) == ArgUse.U) {
